    "Safety First Compliance": "\u0938\u0947\u092b\u094d\u091f\u0940 \u092b\u0930\u094d\u0938\u094d\u091f \u0915\u092e\u094d\u092a\u094d\u0932\u093e\u092f\u0902\u0938",
