    Tablet: "\u091f\u0948\u092c\u0932\u0947\u091f",
    Capsule: "\u0915\u0948\u092a\u094d\u0938\u0942\u0932",
    Metformin: "\u092e\u0947\u091f\u092b\u0949\u0930\u094d\u092e\u093f\u0928",
