    "Diabetes Pedigree Function": "\u0921\u093e\u092f\u092c\u093f\u091f\u0940\u091c\u093c \u092a\u0947\u0921\u093f\u0917\u094d\u0930\u0940 \u092b\u0902\u0915\u094d\u0936\u0928",
    Age: "\u0909\u092e\u094d\u0930",
