    "Medical Report": "\u092e\u0947\u0921\u093f\u0915\u0932 \u0930\u093f\u092a\u094b\u0930\u094d\u091f",
    "Risk analysis ready": "\u0930\u093f\u0938\u094d\u0915 \u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 \u0924\u0948\u092f\u093e\u0930",
